import{_ as e,a as t,b as r,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup और Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/redundant-backup-and-read-source.md","filePath":"hi/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"hi/Other/redundant-backup-and-read-source.md"};function u(s,a,o,h,b,k){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="redundant-backup-और-read-source-switching" tabindex="-1">Redundant Backup और Read Source Switching <a class="header-anchor" href="#redundant-backup-और-read-source-switching" aria-label="Permalink to &quot;Redundant Backup और Read Source Switching&quot;">​</a></h1><p>Redundant backup already uploaded file की एक extra copy store करता है।</p><p>Primary file और backup file दोनों read sources के रूप में इस्तेमाल हो सकती हैं। Visitors को आम तौर पर कोई फर्क नहीं दिखता। फर्क सिर्फ इतना है कि file किस storage channel से serve हो रही है।</p><h2 id="redundant-backup-क्या-कर-सकता-है" tabindex="-1">Redundant Backup क्या कर सकता है <a class="header-anchor" href="#redundant-backup-क्या-कर-सकता-है" aria-label="Permalink to &quot;Redundant Backup क्या कर सकता है&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Extra copy store करना</td><td>Files को दूसरे upload channel पर back up करके single channel failure का risk कम करता है।</td></tr><tr><td>Read source switch करना</td><td>Backup successful होने के बाद file reads को primary channel और backup channel के बीच switch करता है।</td></tr><tr><td>Single-file backup</td><td>File details page से एक file back up करें।</td></tr><tr><td>Batch backup</td><td>Admin page में multiple files select करके साथ में back up करें।</td></tr><tr><td>Global redundant backup</td><td>Other Settings से folder के आधार पर files back up करें।</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>खोलें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>यह entry किसी folder या सभी files में bulk backup जोड़ने के लिए सबसे अच्छी है।</p><p>Backup channel manually select किया जा सकता है, या आप automatic switching चुनकर ImgBed को suitable backup channel खोजने दे सकते हैं।</p><h2 id="file-details-से-backup" tabindex="-1">File Details से Backup <a class="header-anchor" href="#file-details-से-backup" aria-label="Permalink to &quot;File Details से Backup&quot;">​</a></h2><p>Admin panel में file details page खोलें और backup click करें।</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>यह किसी एक important file को on demand back up करने के लिए best है।</p><p>Backup successful होने के बाद file details page available read sources दिखाता है।</p><h2 id="selection-से-batch-backup" tabindex="-1">Selection से Batch Backup <a class="header-anchor" href="#selection-से-batch-backup" aria-label="Permalink to &quot;Selection से Batch Backup&quot;">​</a></h2><p>Admin panel में multiple files select करें और batch backup run करें।</p><p><img src="'+r+'" alt="Batch backup" loading="lazy"></p><p>यह files के group को process करने के लिए best है।</p><p>Selection backup, file details backup और Other Settings के तहत redundant backup एक ही backup system इस्तेमाल करते हैं। ये सिर्फ अलग entry points हैं।</p><h2 id="backup-के-बाद-read-source-switch-करना" tabindex="-1">Backup के बाद Read Source Switch करना <a class="header-anchor" href="#backup-के-बाद-read-source-switch-करना" aria-label="Permalink to &quot;Backup के बाद Read Source Switch करना&quot;">​</a></h2><p>Backup complete होने के बाद file details page read source switch करने देता है:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Original upload channel से read करता है।</td></tr><tr><td>Backup channel</td><td>Backup channel से read करता है।</td></tr></tbody></table><p><img src="'+d+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors को यह जानने की ज़रूरत नहीं कि file primary channel से serve हो रही है या backup channel से।</p><p>आप जो read source चुनते हैं, वही बाद के file access के लिए preferred source बन जाता है।</p><h2 id="backup-कब-skip-होता-है" tabindex="-1">Backup कब Skip होता है <a class="header-anchor" href="#backup-कब-skip-होता-है" aria-label="Permalink to &quot;Backup कब Skip होता है&quot;">​</a></h2><p>Backup के दौरान नीचे के cases skip होते हैं। ये errors नहीं हैं।</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>जिस file का backup पहले से है, उसका backup दोबारा नहीं बनाया जाता।</td></tr><tr><td>Primary और backup channels same हैं</td><td>Meaningful backup के लिए copy दूसरे channel में store होनी चाहिए।</td></tr><tr><td>No usable backup channel</td><td>कोई suitable alternative channel available नहीं है।</td></tr></tbody></table><p>संक्षेप में: backups दूसरे channel में जाने चाहिए, और already backed-up files फिर से extra space consume नहीं करतीं।</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>वह channel जिससे file पहली बार upload हुई थी।</td></tr><tr><td>Backup channel</td><td>वह channel जिसमें redundant copy store है।</td></tr><tr><td>Primary read source</td><td>File अभी primary channel से read हो रही है।</td></tr><tr><td>Backup read source</td><td>File अभी backup channel से read हो रही है।</td></tr></tbody></table><p>Primary और backup read sources का user-facing behavior same है।</p><p>जब तक backup file available है, backup read source पर switch करने के बाद images, videos और download links काम करते रहते हैं।</p><h2 id="file-delete-होने-पर-क्या-होता-है" tabindex="-1">File Delete होने पर क्या होता है <a class="header-anchor" href="#file-delete-होने-पर-क्या-होता-है" aria-label="Permalink to &quot;File Delete होने पर क्या होता है&quot;">​</a></h2><p>File delete करने पर ImgBed primary file और backup file दोनों delete करता है।</p>',37)])])}const g=c(p,[["render",u]]);export{y as __pageData,g as default};
